// hoje em America/Sao_Paulo
const hoje = new Date();

// fim = ontem
const fim = new Date(hoje);
fim.setDate(fim.getDate() - 1);

// início depende do dia da semana
const ini = new Date(fim);

if (hoje.getDay() === 1) {
  // Hoje é segunda → pega de quinta a domingo
  ini.setDate(fim.getDate() - 3);  // quinta
} else if (hoje.getDay() === 4) {
  // Hoje é quinta → pega de segunda a quarta
  ini.setDate(fim.getDate() - 2);  // segunda
} else {
  // fallback: últimos 3 dias
  ini.setDate(fim.getDate() - 2);
}

// formatador dd/mm/yyyy
const fmt = d => String(d.getDate()).padStart(2,'0') + '/' +
                 String(d.getMonth()+1).padStart(2,'0') + '/' +
                 d.getFullYear();

return {
  data_ini: fmt(ini),
  data_fim: fmt(fim)
};

const items = $input.all();
if (!items.length) {
  return [{ json: { prompt: "Nenhuma notícia encontrada no período." } }];
}

// datas vindas do primeiro node "Code" (ajuste o nome se o seu node tiver outro nome)
const { data_ini, data_fim } = $item(0).$node["Code"].json;

// Limita texto da legenda para não estourar token
const MAX = 500;
const cut = s => (s ?? '').toString().trim().slice(0, MAX);

// Monta contexto com título + legenda reduzida
const contexto = items.map(it => {
  const titulo  = (it.json.titulo  ?? '').toString().trim();
  const legenda = cut(it.json.legenda);
  return `• ${titulo}\n${legenda}`;
}).join("\n\n");

// Cabeçalhos
const header1 = `*Bom dia comunidade Radar Corretor!* 📰\n\n`;
const header2 = `Segue *resumo das notícias da semana*:\n\n`;
const header3 = `Acompanhe a nossa página no Instagram:\nhttps://www.instagram.com/radarcorretor\n\n`;

// Opcional: rodapé (deixe vazio se não precisar)
const footer = ``;

const prompt = `
Você é editor do briefing matinal da comunidade Radar Corretor (WhatsApp).
Produza UMA mensagem concisa, didática e visual, com base nas notícias entre ${data_ini} e ${data_fim}.
Não liste notícia por notícia. Não inclua links (além do Instagram já fornecido). Não invente fatos.

BASE (referência; não copie literalmente):
${contexto}

FORMATO EXATO DA SAÍDA (mantenha as linhas fixas e a ordem):
${header1}${header2}${header3}[RESUMO CONECTADO EM BLOCOS]
- Estruture em 2 a 3 blocos, cada um com título em negrito (use negrito do WhatsApp: *texto* - apenas um asterisco, nunca dois)+ emoji na mesma linha (ex.: 📈 Economia, 🏠 Imobiliário, 🤖 Tech/Empresas).
- Cada bloco deve ter 2 a 3 frases curtas, explicando o que aconteceu e por que importa para o corretor.
- Separe os blocos com uma linha em branco.

O que muda para o corretor:
- (emoji) Bullets práticos

[INSIRA AQUI uma ÚNICA linha com **uma frase motivacional de vendas em itálico com autor, formato exato: _"frase" — Autor_]

${footer}

REGRAS:
- PT-BR, claro e objetivo; sem jargão.
- Priorize números/dados quando existirem; se faltarem, não invente.
- Obrigatório: a citação deve vir em itálico (use sublinhados do WhatsApp: _texto_).
- Não adicione seções além das especificadas.
- Mantenha um limite de 1524 caracteres
`.trim();

return [{ json: { prompt } }];

const parseBR = (s) => {
  if (!s) return NaN;
  const [dd, mm, yyyy] = s.split('/');
  return new Date(`${yyyy}-${mm}-${dd}T00:00:00-03:00`).getTime();
};

// pega o intervalo vindo do primeiro Code
const data_ini = $item(0).$node["Code"].json.data_ini;
const data_fim = $item(0).$node["Code"].json.data_fim;
const tIni = parseBR(data_ini);
const tFim = parseBR(data_fim);

const out = $input.all().filter(it => {
  const st = (it.json.status || '').toLowerCase();
  const t  = parseBR(it.json.data_processamento);
  return st === 'postado' && !Number.isNaN(t) && t >= tIni && t <= tFim;
});

return out;

// n8n Code node – pega o base64 do arquivo baixado no "Download file"

const binAll = $input.item.binary || {};

// tenta 'imagem_final', depois 'data', depois a 1ª chave disponível
const key =
  binAll.imagem_final ? 'imagem_final' :
  (binAll.data ? 'data' : Object.keys(binAll)[0]);

if (!key) throw new Error('Nenhum binário encontrado no item.');

const bin = binAll[key];
if (!bin?.data) throw new Error(`Binário na chave "${key}" não possui .data.`);

// já vem em base64; não reconverta
const base64 = bin.data;

return {
  json: {
    base64Image: base64,                          // use isto no Evolution (media)
    mimeType: bin.mimeType || 'application/octet-stream',
    fileName: bin.fileName || 'arquivo'
  }
};
